import{_ as a,o as t,c as o,a2 as n}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Core Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"start/core-concepts.md","filePath":"start/core-concepts.md","lastUpdated":null}'),r={name:"start/core-concepts.md"};function s(i,e,d,c,l,p){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h1><p>Autofac makes agentic delivery inspectable by turning each run into a process, not a transcript. These are the concepts you will see throughout the product and API.</p><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><p>A workflow is a BPMN process definition. It describes the order of work, agent tasks, approval gates, wait states, timers, and external-event correlations. A published workflow can be started manually or by an integration trigger.</p><h2 id="run" tabindex="-1">Run <a class="header-anchor" href="#run" aria-label="Permalink to &quot;Run&quot;">​</a></h2><p>A run is one execution of a workflow. It has a status, current step, risk level, initiator, timestamps, step history, context values, approvals, artifacts, and evidence.</p><p>Common run statuses include:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>running</code></td><td>The engine is actively advancing or dispatching work.</td></tr><tr><td><code>awaiting_approval</code></td><td>A human approval task is pending.</td></tr><tr><td><code>waiting_user</code></td><td>An agent asked a human a blocking question.</td></tr><tr><td><code>completed</code></td><td>The workflow reached its end event.</td></tr><tr><td><code>failed</code></td><td>A step failed and the run could not continue automatically.</td></tr></tbody></table><h2 id="agent-task" tabindex="-1">Agent task <a class="header-anchor" href="#agent-task" aria-label="Permalink to &quot;Agent task&quot;">​</a></h2><p>An agent task is a BPMN task with an <code>autofac:agentTask</code> extension. It names the agent, action, purpose, policy tag, permission level, sandbox profile, and prompt. Some actions call deterministic tools without spending model tokens.</p><h2 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h2><p>An agent is a Markdown profile with YAML frontmatter and a prompt body. The profile declares tools, denied tools, supported actions, environments, policy tags, and allowed sandbox profiles.</p><h2 id="skill" tabindex="-1">Skill <a class="header-anchor" href="#skill" aria-label="Permalink to &quot;Skill&quot;">​</a></h2><p>A skill is reusable Markdown guidance. Agents can load skills based on action bindings or workflow runtime contracts. Skills are guidance unless a runtime contract marks one as required.</p><h2 id="tool-gateway" tabindex="-1">Tool Gateway <a class="header-anchor" href="#tool-gateway" aria-label="Permalink to &quot;Tool Gateway&quot;">​</a></h2><p>The Tool Gateway brokers tool and connector calls. It checks permissions and policy before the action runs, records the decision, and ensures actions stay within the task&#39;s allowed surface.</p><h2 id="policy-decision" tabindex="-1">Policy decision <a class="header-anchor" href="#policy-decision" aria-label="Permalink to &quot;Policy decision&quot;">​</a></h2><p>Policy decisions can allow, escalate, or reject an action. Decisions carry risk information and rationale so operators can understand why a run continued, paused, or stopped.</p><h2 id="approval-task" tabindex="-1">Approval task <a class="header-anchor" href="#approval-task" aria-label="Permalink to &quot;Approval task&quot;">​</a></h2><p>An approval task is a BPMN user task with an <code>autofac:approvalTask</code> extension. It creates an approval request, pauses the run, and resumes only after an approver posts a decision.</p><h2 id="sandbox-profile" tabindex="-1">Sandbox profile <a class="header-anchor" href="#sandbox-profile" aria-label="Permalink to &quot;Sandbox profile&quot;">​</a></h2><p>Sandbox profiles describe the execution boundary for code-producing or tool-heavy work. Autofac supports Docker, OpenSandbox, and Kubernetes-backed providers. Profiles such as <code>offline</code>, <code>repo-read</code>, <code>repo-write</code>, and <code>deployment</code> shape network and repository access.</p><h2 id="evidence-pack" tabindex="-1">Evidence pack <a class="header-anchor" href="#evidence-pack" aria-label="Permalink to &quot;Evidence pack&quot;">​</a></h2><p>The evidence pack is a structured record of a run. It includes redacted prompt snapshots, model usage, tool invocations, policy decisions, sandbox executions, approvals, artifacts, audit entries, and the workflow BPMN hash.</p>',24)])])}const k=a(r,[["render",s]]);export{u as __pageData,k as default};
